import type { SplitterPanelData } from '@ark-ui/react/splitter';
import {
  createSplitterRegistry,
  Splitter as SplitterPrimitive,
  useSplitter,
  useSplitterContext,
} from '@ark-ui/react/splitter';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, CSSProperties } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Splitter.module.css';

const rootStyle = {
  width: 'var(--moduix-splitter-width, 100%)',
  height: 'var(--moduix-splitter-height, 28rem)',
} satisfies CSSProperties;

const SplitterRoot = forwardRef<
  ComponentRef<typeof SplitterPrimitive.Root>,
  ComponentProps<typeof SplitterPrimitive.Root>
>(function SplitterRoot({ className, style, ...props }, ref) {
  return (
    <SplitterPrimitive.Root
      ref={ref}
      data-slot="splitter-root"
      className={clsx(styles.root, normalizeClassName(className))}
      style={{ ...rootStyle, ...style }}
      {...props}
    />
  );
});

const SplitterRootProvider = forwardRef<
  ComponentRef<typeof SplitterPrimitive.RootProvider>,
  ComponentProps<typeof SplitterPrimitive.RootProvider>
>(function SplitterRootProvider({ className, style, ...props }, ref) {
  return (
    <SplitterPrimitive.RootProvider
      ref={ref}
      data-slot="splitter-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      style={{ ...rootStyle, ...style }}
      {...props}
    />
  );
});

const SplitterPanel = forwardRef<
  ComponentRef<typeof SplitterPrimitive.Panel>,
  ComponentProps<typeof SplitterPrimitive.Panel>
>(function SplitterPanel({ className, ...props }, ref) {
  return (
    <SplitterPrimitive.Panel
      ref={ref}
      data-slot="splitter-panel"
      className={clsx(styles.panel, normalizeClassName(className))}
      {...props}
    />
  );
});

const SplitterResizeTriggerIndicator = forwardRef<
  ComponentRef<typeof SplitterPrimitive.ResizeTriggerIndicator>,
  ComponentProps<typeof SplitterPrimitive.ResizeTriggerIndicator>
>(function SplitterResizeTriggerIndicator({ className, ...props }, ref) {
  return (
    <SplitterPrimitive.ResizeTriggerIndicator
      ref={ref}
      data-slot="splitter-resize-trigger-indicator"
      className={clsx(styles.resizeTriggerIndicator, normalizeClassName(className))}
      {...props}
    />
  );
});

const SplitterResizeTrigger = forwardRef<
  ComponentRef<typeof SplitterPrimitive.ResizeTrigger>,
  ComponentProps<typeof SplitterPrimitive.ResizeTrigger>
>(function SplitterResizeTrigger({ children, className, ...props }, ref) {
  return (
    <SplitterPrimitive.ResizeTrigger
      ref={ref}
      data-slot="splitter-resize-trigger"
      className={clsx(styles.resizeTrigger, normalizeClassName(className))}
      {...props}
    >
      {children === undefined ? <SplitterResizeTriggerIndicator /> : children}
    </SplitterPrimitive.ResizeTrigger>
  );
});

const Splitter = Object.assign(SplitterRoot, {
  Root: SplitterRoot,
  RootProvider: SplitterRootProvider,
  Panel: SplitterPanel,
  ResizeTrigger: SplitterResizeTrigger,
  ResizeTriggerIndicator: SplitterResizeTriggerIndicator,
});

export {
  createSplitterRegistry,
  Splitter,
  type SplitterPanelData,
  useSplitter,
  useSplitterContext,
};

@layer moduix.components {
  .root {
    position: relative;
    box-sizing: border-box;
    display: flex;
    min-width: var(--moduix-splitter-min-width, 0);
    min-height: var(--moduix-splitter-min-height, 0);
    overflow: hidden;
    border: var(--moduix-splitter-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-splitter-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-splitter-radius, var(--moduix-radius-md));
    background-color: var(--moduix-splitter-bg, var(--moduix-color-card));
    color: var(--moduix-splitter-color, var(--moduix-color-foreground));
    box-shadow: var(--moduix-splitter-shadow, var(--moduix-shadow-sm));

    &[data-orientation='vertical'] {
      flex-direction: column;
    }

    &[data-dragging] {
      cursor: col-resize;

      &[data-orientation='vertical'] {
        cursor: row-resize;
      }
    }
  }

  .panel {
    box-sizing: border-box;
    min-width: var(--moduix-splitter-panel-min-width, 0);
    min-height: var(--moduix-splitter-panel-min-height, 12.5rem);
    padding: var(--moduix-splitter-panel-padding, var(--moduix-spacing-4));
    overflow: auto;
    border: var(--moduix-splitter-panel-border-width, 0) solid
      var(--moduix-splitter-panel-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-splitter-panel-radius, 0);
    background-color: var(--moduix-splitter-panel-bg, var(--moduix-color-card));
    color: var(--moduix-splitter-panel-color, var(--moduix-color-card-foreground));
    box-shadow: var(--moduix-splitter-panel-shadow, none);

    &[data-dragging] {
      user-select: none;
    }
  }

  .root[data-orientation='vertical'] > .panel {
    min-height: var(--moduix-splitter-panel-min-height-vertical, 0);
  }

  .resizeTrigger {
    position: relative;
    z-index: 1;
    box-sizing: border-box;
    display: flex;
    flex: 0 0 var(--moduix-splitter-resize-trigger-line-size, 1px);
    align-items: center;
    justify-content: center;
    width: var(--moduix-splitter-resize-trigger-line-size, 1px);
    min-width: var(--moduix-splitter-resize-trigger-line-size, 1px);
    padding: 0;
    border: 0;
    background-color: var(--moduix-splitter-resize-trigger-bg, transparent);
    appearance: none;
    cursor: col-resize;
    outline: 0;
    touch-action: none;
    transition: opacity var(--moduix-splitter-transition, var(--moduix-transition-default));

    &::before {
      position: absolute;
      width: var(--moduix-splitter-resize-trigger-line-thickness, 0.5px);
      height: var(--moduix-splitter-resize-trigger-line-length, 100%);
      border-radius: var(--moduix-splitter-resize-trigger-line-radius, var(--moduix-radius-full));
      background-color: var(
        --moduix-splitter-resize-trigger-line-color,
        var(--moduix-color-border)
      );
      content: '';
      transition:
        background-color var(--moduix-splitter-transition, var(--moduix-transition-default)),
        opacity var(--moduix-splitter-transition, var(--moduix-transition-default));
    }

    &::after {
      position: absolute;
      z-index: 1;
      width: var(--moduix-splitter-resize-trigger-size, var(--moduix-spacing-2-5));
      height: 100%;
      content: '';
    }

    &[data-orientation='vertical'] {
      width: 100%;
      min-width: 0;
      height: var(--moduix-splitter-resize-trigger-line-size, 1px);
      min-height: var(--moduix-splitter-resize-trigger-line-size, 1px);
      cursor: row-resize;

      &::before {
        width: var(--moduix-splitter-resize-trigger-line-length, 100%);
        height: var(--moduix-splitter-resize-trigger-line-thickness, 0.5px);
      }

      &::after {
        width: 100%;
        height: var(--moduix-splitter-resize-trigger-size, var(--moduix-spacing-2-5));
      }
    }

    &[data-dragging] {
      &::before {
        background-color: var(
          --moduix-splitter-resize-trigger-line-color-dragging,
          color-mix(
            in oklab,
            var(--moduix-splitter-resize-trigger-line-color, var(--moduix-color-border)) 72%,
            var(--moduix-color-muted-foreground)
          )
        );
      }
    }

    &[data-disabled] {
      cursor: default;
      opacity: var(--moduix-splitter-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  @media (hover: hover) {
    .resizeTrigger:hover:not(:disabled, [data-disabled]) {
      &::before {
        background-color: var(
          --moduix-splitter-resize-trigger-line-color-hover,
          color-mix(
            in oklab,
            var(--moduix-splitter-resize-trigger-line-color, var(--moduix-color-border)) 72%,
            var(--moduix-color-muted-foreground)
          )
        );
      }
    }
  }

  .resizeTriggerIndicator {
    position: absolute;
    inset-block-start: 50%;
    inset-inline-start: 50%;
    z-index: 2;
    box-sizing: border-box;
    width: var(--moduix-splitter-resize-trigger-indicator-width, var(--moduix-spacing-1-5));
    height: var(--moduix-splitter-resize-trigger-indicator-height, var(--moduix-size-xs));
    border: var(
        --moduix-splitter-resize-trigger-indicator-border-width,
        var(--moduix-border-width-sm)
      )
      solid var(--moduix-splitter-resize-trigger-indicator-border-color, var(--moduix-color-border));
    border-radius: var(
      --moduix-splitter-resize-trigger-indicator-radius,
      var(--moduix-radius-full)
    );
    background-color: var(
      --moduix-splitter-resize-trigger-indicator-bg,
      var(--moduix-color-background)
    );
    box-shadow: var(--moduix-splitter-resize-trigger-indicator-shadow, var(--moduix-shadow-sm));
    pointer-events: none;
    transform: translate(-50%, -50%);
    transition:
      border-color var(--moduix-splitter-transition, var(--moduix-transition-default)),
      box-shadow var(--moduix-splitter-transition, var(--moduix-transition-default)),
      transform var(--moduix-splitter-transition, var(--moduix-transition-default));

    &[data-orientation='vertical'] {
      width: var(--moduix-splitter-resize-trigger-indicator-height, var(--moduix-size-xs));
      height: var(--moduix-splitter-resize-trigger-indicator-width, var(--moduix-spacing-1-5));
    }
  }

  .resizeTrigger[data-dragging] .resizeTriggerIndicator {
    border-color: var(
      --moduix-splitter-resize-trigger-indicator-border-color-dragging,
      var(--moduix-splitter-resize-trigger-indicator-border-color, var(--moduix-color-border))
    );
    background-color: var(
      --moduix-splitter-resize-trigger-indicator-bg-dragging,
      var(--moduix-splitter-resize-trigger-indicator-bg, var(--moduix-color-background))
    );
    box-shadow: var(
      --moduix-splitter-resize-trigger-indicator-shadow-dragging,
      var(--moduix-shadow-md)
    );
    transform: translate(-50%, -50%) scale(1.08);
  }

  @media (hover: hover) {
    .resizeTrigger:hover:not(:disabled, [data-disabled]) .resizeTriggerIndicator {
      border-color: var(
        --moduix-splitter-resize-trigger-indicator-border-color-hover,
        color-mix(
          in oklab,
          var(--moduix-splitter-resize-trigger-indicator-border-color, var(--moduix-color-border))
            72%,
          var(--moduix-color-muted-foreground)
        )
      );
      box-shadow: var(
        --moduix-splitter-resize-trigger-indicator-shadow-hover,
        var(--moduix-shadow-md)
      );
    }
  }

  .resizeTrigger[data-disabled] .resizeTriggerIndicator {
    visibility: hidden;
  }
}

export {
  createSplitterRegistry,
  Splitter,
  type SplitterPanelData,
  useSplitter,
  useSplitterContext,
} from './Splitter';
